import pytest
import uuid

def test_decision_table_role_action_matrix(api_client, joint_account, primary_auth_headers, secondary_auth_headers):
    account_id = joint_account["id"]
    txn_payload = {"type": "debit", "amount": 10, "currency": "USD"}
    own_payload = {"action": "transfer_ownership", "new_owner_id": "user-888"}

    cases = [
        (primary_auth_headers,   txn_payload, (200, 201), "primary+txn"),
        (secondary_auth_headers, txn_payload, (200, 201), "secondary+txn"),
        (primary_auth_headers,   own_payload, (200, 201), "primary+ownership"),
        (secondary_auth_headers, own_payload, (403,),     "secondary+ownership"),
    ]

    for auth_headers, payload, expected_codes, label in cases:
        headers = {**auth_headers, "Idempotency-Key": str(uuid.uuid4())}
        resp = api_client.post(f"/accounts/{account_id}/joint", json=payload, headers=headers)
        assert resp.status_code in expected_codes, (
            f"[{label}] Expected {expected_codes} got {resp.status_code}"
        )
